class_overrides.wrapper_classes:
{% set wrapper_classes = ['rvo-alert', 'rvo-alert--' + kind] %}
{% if padding %}{% set wrapper_classes = wrapper_classes + ['rvo-alert--padding-' + padding] %}{% endif %}
{% if maxWidth %}{% set wrapper_classes = wrapper_classes + ['rvo-alert--layout'] %}{% endif %}
{% if _component_context.get('class') %}{% set wrapper_classes = wrapper_classes + _component_context['class'].split() %}{% endif %}

custom_content_template:
{% set status_icon_map = {'info': 'info', 'warning': 'waarschuwing', 'error': 'foutmelding', 'success': 'bevestiging'} %}
        <span class="utrecht-icon rvo-icon rvo-icon-{{ status_icon_map[kind] }} rvo-status-icon rvo-status-icon-{{ status_icon_map[kind] }} rvo-icon--xl"
            role="img" aria-label="{{ status_icon_map[kind] | title }}"></span>
        <div class="rvo-alert-text">
            {% if heading %}<strong>{{ heading }}</strong>{% endif %}
            <div>{{ children if children else content | safe }}</div>
        </div>
        {% if closable %}
            <button type="button" class="utrecht-button utrecht-button--subtle rvo-button__close" aria-label="Sluiten">
                <span class="utrecht-icon rvo-icon rvo-icon-kruis rvo-icon--md"
                    role="img" aria-label="Kruis"></span>
            </button>
        {% endif %}
